import{c as s}from"./Cdp7ABTo.js";const o={async getApprovalStats(a){try{return(await s.get(`/faculty/${a}/approval-stats`)).data}catch{return{case_records:0,discharge_summaries:0,admissions:0,prescriptions:0,total:0}}},async getPendingApprovals(a,t){try{return(await s.get(`/faculty/${a}/approvals`,{params:{status:"PENDING",type:t}})).data}catch{return[]}},async getApprovalHistory(a){try{return(await s.get(`/faculty/${a}/approval-history`)).data}catch{return[]}},async processApproval(a,t,r){await s.put(`/faculty/${a}/approvals/${t}`,r)},async getTodaySchedule(a){try{return(await s.get(`/faculty/${a}/today-schedule`)).data}catch{return[]}}};export{o as a};
